`,s.jsx(t.p,{children:s.jsx(t.img,{src:"/blogs/best-nepali-board-games/samrajya.png",alt:"Samrajya Board"})}),`
`,s.jsx(t.p,{children:"You roll the dice, move your token, and follow what the board says. Cards throw in a bit of randomness. The goal is to conquer the valley, just like Prithvi Narayan Shah did."}),`
